// --- HTTP Server acting as the API Gateway ---

function createGatewayServer(grpcServerAddress, httpPort) {
  const gatewayClient = new GrpcGatewayClient(grpcServerAddress);

  const server = http.createServer(async (req, res) => {
    console.log(`\n[HTTP] Received ${req.method} ${req.url}`);
    console.log(`[HTTP] Headers: ${JSON.stringify(req.headers, null, 2)}`);

    // Collect request body
    let body = '';
    req.on('data', (chunk) => {
      body += chunk.toString();
    });

    req.on('end', async () => {
      try {
        const parsedUrl = url.parse(req.url, true);
        const pathParts = parsedUrl.pathname.split('/').filter(Boolean);

        // Route: GET /resource/:id -> gRPC GetResource
        if (
          req.method === 'GET' &&
          pathParts.length === 2 &&
          pathParts[0] === 'resource'
        ) {
          const resourceId = pathParts[1];
          try {
            const grpcResponse = await gatewayClient.getResource(
              req,
              resourceId
            );
            res.writeHead(200, { 'Content-Type': 'application/json' });
            res.end(JSON.stringify(grpcResponse));
          } catch (grpcError) {
            const statusCode = mapGrpcErrorToHttp(grpcError);
            res.writeHead(statusCode, { 'Content-Type': 'application/json' });
            res.end(
              JSON.stringify({
                error: grpcError.message,
                code: grpcError.code,
              })
            );
          }
          return;
        }

        // Default route: Forward everything else to gRPC ProcessRequest
        try {
          const grpcResponse = await gatewayClient.processRequest(req, body);
          const httpStatus = grpcResponse.status_code || 200;
          const responseHeaders = { 'Content-Type': 'application/json' };

          // Forward response headers from gRPC back to HTTP
          if (grpcResponse.headers) {
            for (const [key, value] of Object.entries(grpcResponse.headers)) {
              responseHeaders[key] = value;
            }
          }

          res.writeHead(httpStatus, responseHeaders);
          res.end(grpcResponse.body || JSON.stringify(grpcResponse));
        } catch (grpcError) {
          const statusCode = mapGrpcErrorToHttp(grpcError);
          res.writeHead(statusCode, { 'Content-Type': 'application/json' });
          res.end(
            JSON.stringify({
              error: grpcError.message,
              code: grpcError.code,
            })
          );
        }
      } catch (err) {
        console.error(`[HTTP] Unexpected error: ${err.message}`);
        res.writeHead(500, { 'Content-Type': 'application/json' });
        res.end(JSON.stringify({ error: 'Internal gateway error' }));
      }
    });
  });

  server.listen(httpPort, () => {
    console.log(`[Gateway] HTTP server listening on port ${httpPort}`);
    console.log(
      `[Gateway] Forwarding requests to gRPC backend at ${grpcServerAddress}`
    );
  });

  // Graceful shutdown
  process.on('SIGINT', () => {
    console.log('\n[Gateway] Shutting down...');
    gatewayClient.close();
    server.close(() => {
      console.log('[Gateway] Server closed.');
      process.exit(0);
    });
  });

  return server;
}

/**
 * Maps gRPC error codes to HTTP status codes
 */
function mapGrpcErrorToHttp(grpcError) {
  const grpcToHttpMap = {
    [grpc.status.OK]: 200,
    [grpc.status.CANCELLED]: 499,
    [grpc.status.UNKNOWN]: 500,
    [grpc.status.INVALID_ARGUMENT]: 400,
    [grpc.status.DEADLINE_EXCEEDED]: 504,
    [grpc.status.NOT_FOUND]: 404,
    [grpc.status.ALREADY_EXISTS]: 409,
    [grpc.status.PERMISSION_DENIED]: 403,
    [grpc.status.RESOURCE_EXHAUSTED]: 429,
    [grpc.status.FAILED_PRECONDITION]: 412,
    [grpc.status.ABORTED]: 409,
    [grpc.status.OUT_OF_RANGE]: 400,
    [grpc.status.UNIMPLEMENTED]: 501,
    [grpc.status.INTERNAL]: 500,
    [grpc.status.UNAVAILABLE]: 503,
    [grpc.status.DATA_LOSS]: 500,
    [grpc.status.UNAUTHENTICATED]: 401,
  };

  return grpcToHttpMap[grpcError.code] || 500;
}

